import React, { useEffect, useState } from 'react';
import { Link } from 'react-router-dom';

const Subscription = () => {
  const [status, setStatus] = useState(null);
  const [loading, setLoading] = useState(true);
  const [error, setError] = useState('');
  const [subscribing, setSubscribing] = useState(false);
  const [selectedPlan, setSelectedPlan] = useState('basic');

  const fetchStatus = async () => {
    setLoading(true);
    setError('');
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        setLoading(false);
        return;
      }

      const res = await fetch('/api/subscription/status', {
        headers: { 'Authorization': `Bearer ${token}` }
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Failed to fetch status');
      setStatus(data.isSubscribed ? 'active' : 'inactive');
    } catch (err) {
      setError(err.message);
    } finally {
      setLoading(false);
    }
  };

  useEffect(() => { fetchStatus(); }, []);

  const handleSubscribe = async () => {
    setSubscribing(true);
    setError('');
    try {
      const token = localStorage.getItem('token');
      if (!token) {
        alert('Please login to subscribe');
        return;
      }

      const res = await fetch('/api/subscription/subscribe', {
        method: 'POST',
        headers: { 
          'Authorization': `Bearer ${token}`,
          'Content-Type': 'application/json'
        },
        body: JSON.stringify({ plan: selectedPlan })
      });
      const data = await res.json();
      if (!res.ok) throw new Error(data.message || 'Subscription failed');
      setStatus('active');
      alert('Subscription successful! Welcome to Netflix!');
    } catch (err) {
      setError(err.message);
    } finally {
      setSubscribing(false);
    }
  };

  const plans = [
    {
      id: 'basic',
      name: 'Basic',
      price: '$8.99',
      period: 'month',
      features: [
        'Good video quality',
        'Watch on your TV or computer',
        'Unlimited movies and TV shows',
        'Cancel anytime'
      ],
      popular: false
    },
    {
      id: 'standard',
      name: 'Standard',
      price: '$13.99',
      period: 'month',
      features: [
        'Better video quality',
        'Watch on your TV, computer, or mobile device',
        'Unlimited movies and TV shows',
        'Watch on 2 screens at the same time',
        'Cancel anytime'
      ],
      popular: true
    },
    {
      id: 'premium',
      name: 'Premium',
      price: '$17.99',
      period: 'month',
      features: [
        'Best video quality',
        'Watch on your TV, computer, or mobile device',
        'Unlimited movies and TV shows',
        'Watch on 4 screens at the same time',
        '4K + HDR content available',
        'Cancel anytime'
      ],
      popular: false
    }
  ];

  if (loading) return (
    <div className="subscription-loading">
      <div className="loading-spinner"></div>
      <p>Loading subscription status...</p>
    </div>
  );

  if (error) return (
    <div className="subscription-error">
      <h2>Error</h2>
      <p style={{ color: 'red' }}>{error}</p>
      <Link to="/" className="back-home">Back to Home</Link>
    </div>
  );

  return (
    <div className="subscription-page">
      <div className="subscription-header">
        <h1>Choose the plan that's right for you</h1>
        <p>All plans include a 30-day money-back guarantee</p>
      </div>

      {status === 'active' ? (
        <div className="subscription-active">
          <div className="success-card">
            <h2>🎉 You're Already Subscribed!</h2>
            <p>Enjoy unlimited movies and TV shows on Netflix.</p>
            <div className="subscription-details">
              <p><strong>Status:</strong> Active</p>
              <p><strong>Plan:</strong> {selectedPlan.charAt(0).toUpperCase() + selectedPlan.slice(1)}</p>
            </div>
            <Link to="/" className="watch-now-btn">Start Watching</Link>
          </div>
        </div>
      ) : (
        <div className="subscription-plans">
          <div className="plans-container">
            {plans.map((plan) => (
              <div 
                key={plan.id} 
                className={`plan-card ${plan.popular ? 'popular' : ''} ${selectedPlan === plan.id ? 'selected' : ''}`}
                onClick={() => setSelectedPlan(plan.id)}
              >
                {plan.popular && <div className="popular-badge">MOST POPULAR</div>}
                <h3>{plan.name}</h3>
                <div className="plan-price">
                  <span className="price">{plan.price}</span>
                  <span className="period">/{plan.period}</span>
                </div>
                <ul className="plan-features">
                  {plan.features.map((feature, index) => (
                    <li key={index}>✓ {feature}</li>
                  ))}
                </ul>
                <button 
                  className={`select-plan-btn ${selectedPlan === plan.id ? 'selected' : ''}`}
                  onClick={(e) => {
                    e.stopPropagation();
                    setSelectedPlan(plan.id);
                  }}
                >
                  {selectedPlan === plan.id ? 'Selected' : 'Select Plan'}
                </button>
              </div>
            ))}
          </div>

          <div className="subscription-actions">
            <button 
              className="subscribe-btn"
              onClick={handleSubscribe}
              disabled={subscribing}
            >
              {subscribing ? 'Processing...' : `Subscribe to ${plans.find(p => p.id === selectedPlan)?.name}`}
            </button>
            <p className="terms">
              By subscribing, you agree to our Terms of Service and Privacy Policy.
            </p>
          </div>
        </div>
      )}

      <div className="subscription-footer">
        <h3>Why Choose Netflix?</h3>
        <div className="benefits">
          <div className="benefit">
            <h4>🎬 Unlimited Entertainment</h4>
            <p>Watch thousands of movies and TV shows</p>
          </div>
          <div className="benefit">
            <h4>📱 Watch Anywhere</h4>
            <p>Stream on your phone, tablet, laptop, and TV</p>
          </div>
          <div className="benefit">
            <h4>🚫 No Ads</h4>
            <p>Enjoy uninterrupted viewing without commercials</p>
          </div>
          <div className="benefit">
            <h4>⏸️ Pause & Resume</h4>
            <p>Pick up where you left off on any device</p>
          </div>
        </div>
      </div>
    </div>
  );
};

export default Subscription;
